from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["external-skills-lab-registry-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>External Skills Labs</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#123256,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:120px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>External Skills Lab Registry</h1><p class="muted">Auto-evolução controlada: avaliar repos externas, criar plano de lab/workflow, decidir reutilização e manter tudo gated.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="seed()">Seed labs</button><button onclick="dashboard()">Dashboard</button></div></section><section class="panel"><h2>Avaliar nova repo externa</h2><div class="grid"><input id="repo" value="openai/skills"/><input id="goal" value="Melhorar skills runtime e evolução controlada do God Mode"/></div><textarea id="desc">Repo externa com skills, agentes, exemplos ou padrões reutilizáveis para projetos ou para evolução do próprio God Mode.</textarea><button onclick="assess()">Avaliar repo + criar plano se servir</button></section><section class="panel"><h2>Decidir reutilização para pedido</h2><textarea id="request">Quero que o God Mode use os labs de skills para decidir que código/padrão reutilizar e como evoluir o próprio sistema com PR, gates e testes.</textarea><div class="grid"><input id="project" value="GOD_MODE"/><input id="area" value="skills self evolution"/></div><button onclick="reuse()">Decidir reutilização</button></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function show(x){qs('#out').textContent=JSON.stringify(x,null,2)}async function seed(){show(await api('/api/external-skills-lab-registry/seed-defaults',{method:'POST'}))}async function dashboard(){show(await api('/api/external-skills-lab-registry/dashboard'))}async function assess(){show(await api('/api/external-skills-lab-registry/assess-repo',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({repo_full_name:qs('#repo').value,description:qs('#desc').value,operator_goal:qs('#goal').value})}))}async function reuse(){show(await api('/api/external-skills-lab-registry/decide-reuse',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({operator_request:qs('#request').value,target_project:qs('#project').value,target_area:qs('#area').value})}))}dashboard()</script></body></html>
"""


@router.get('/app/external-skills-lab-registry', response_class=HTMLResponse)
async def external_skills_lab_registry_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/skills-labs', response_class=HTMLResponse)
async def skills_labs_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
